import json
from pathlib import Path

class TimerScoreboard:
    def __init__(self, root='.'):
        self.root = Path(root)
        self.ip = 'timer'
        self.events_path = self.root / self.ip / 'sim' / 'scoreboard_events.jsonl'
        self.events_path.parent.mkdir(parents=True, exist_ok=True)
        self.goals = self._load_goals()
        self.model = self._load_model()
        self.failures = []

    def _load_goals(self):
        p = self.root / self.ip / 'verify' / 'equivalence_goals.json'
        with p.open() as f:
            data = json.load(f)
        if isinstance(data, dict):
            return data.get('goals', data.get('equivalence_goals', []))
        return data

    def _load_model(self):
        import importlib.util
        p = self.root / self.ip / 'model' / 'functional_model.py'
        spec = importlib.util.spec_from_file_location('timer_functional_model', p)
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)
        return mod.FunctionalModel()

    def apply_expected(self, transaction):
        if not hasattr(self.model, 'apply'):
            raise AssertionError('FunctionalModel.apply is required')
        return self.model.apply(transaction)

    def check(self, scenario_id, cycle, stimulus, rtl_observed, coverage_refs=None, goal_id=None):
        coverage_refs = coverage_refs or []
        fl_expected = self.apply_expected(stimulus)
        passed = fl_expected == rtl_observed
        row = {
            'goal_id': goal_id or self._default_goal_id(),
            'scenario_id': scenario_id,
            'cycle': cycle,
            'stimulus': stimulus,
            'fl_expected': fl_expected,
            'rtl_observed': rtl_observed,
            'passed': passed,
            'mismatch': None if passed else {'expected': fl_expected, 'got': rtl_observed},
            'coverage_refs': coverage_refs
        }
        with self.events_path.open('a') as f:
            f.write(json.dumps(row, default=str) + '\n')
        if not passed:
            self.failures.append(row)
            raise AssertionError(f"{scenario_id} mismatch expected={fl_expected} got={rtl_observed}")
        return row

    def _default_goal_id(self):
        if self.goals:
            g = self.goals[0]
            if isinstance(g, dict):
                return g.get('goal_id') or g.get('id') or 'goal_0'
        return 'goal_0'

    def final_check(self):
        if self.failures:
            raise AssertionError(f'{len(self.failures)} scoreboard failures')

import json
from pathlib import Path
from transactions import TimerTransaction

class TimerSequences:
    def __init__(self, root='.'):
        self.root = Path(root)
        self.contract = self._load_contract()
        self.goals = self._load_goals()

    def _load_contract(self):
        p = self.root / 'timer' / 'rtl' / 'rtl_contract.json'
        with p.open() as f:
            return json.load(f)

    def _load_goals(self):
        p = self.root / 'timer' / 'verify' / 'equivalence_goals.json'
        with p.open() as f:
            data = json.load(f)
        return data.get('goals', data.get('equivalence_goals', data)) if isinstance(data, dict) else data

    def reset_sequence(self):
        yield TimerTransaction('SC_RESET', 'reset', {}, {}, self._goal_id(0))

    def representative_sequence(self):
        yield TimerTransaction('SC_REPRESENTATIVE', 'goal_stimulus', {'goal_index': 0}, {}, self._goal_id(0))

    def full_regression(self):
        for i, _ in enumerate(self.goals):
            yield TimerTransaction(f'SC_GOAL_{i}', 'goal_stimulus', {'goal_index': i}, {}, self._goal_id(i))

    def _goal_id(self, i):
        if i < len(self.goals) and isinstance(self.goals[i], dict):
            return self.goals[i].get('goal_id') or self.goals[i].get('id') or f'goal_{i}'
        return f'goal_{i}'

import json
from pathlib import Path

class TimerCoverage:
    def __init__(self, root='.'):
        self.root = Path(root)
        self.bins = {}

    def sample(self, scenario_id, refs=None):
        self.bins[scenario_id] = self.bins.get(scenario_id, 0) + 1
        for r in refs or []:
            self.bins[str(r)] = self.bins.get(str(r), 0) + 1

    def write(self):
        p = self.root / 'timer' / 'cov' / 'coverage_functional.json'
        p.parent.mkdir(parents=True, exist_ok=True)
        with p.open('w') as f:
            json.dump({'functional_bins': self.bins}, f, indent=2)

class TimerDriver:
    def __init__(self, dut=None):
        self.dut = dut

    async def drive(self, transaction):
        return transaction

class TimerMonitor:
    def __init__(self, dut=None):
        self.dut = dut
        self.cycle = 0

    async def observe(self, driven_transaction):
        self.cycle += 1
        return driven_transaction.payload

